module binary_up_counter
(
  input rst_n,
  input clk_inv,
  input en,

  output reg [3:0] out
);

  always @(posedge clk_inv or negedge rst_n) begin
    if (!rst_n)
	begin
      out <= 4'b0000;
    end

	else if (en) 
	begin
      out <= out + 1;
    end

	else 
	begin
      out <= out;
    end
  end

endmodule
